mapper.select:
/* ====== cmn.batchlogsrch.selectList =========*/
SELECT a.BTCH_PRGM_ID , TO_CHAR(a.OPRT_STRT_TM, 'YYYY-MM-DD HH24:MI:SS') OPRT_STRT_TM , a.OPRT_DM , a.REMRK , a.ERR_DSC , a.ERR_CD , a.ERR_CD || '-' || a.ERR_DSC RESULT , a.OPRT_STAT /* 상태 */ , a.OPRT_TYPE , TO_CHAR(a.OPRT_END_DT, 'YYYY-MM-DD HH24:MI:SS') OPRT_END_DT , a.REGST_ID , TO_CHAR(a.REGST_DTTM, 'YYYY-MM-DD HH24:MI:SS') REGST_DTTM , b.BTCH_PRGM_NM , b.BTCH_TYPE , b.FLFIL_CYCL /* 실행주기 */ , b.USG_YN /* 사용여부 */ FROM CMN_BATCH_LOG_MGNT_MST a, CMN_BTCH_PRGM_MGMT b where a.btch_prgm_id = b.btch_prgm_id(+)
AND b.BTCH_PRGM_NM like '%' || #{searchBtchPrgmNm} || '%'
AND A.OPRT_DM >= #{searchStrtDt}
AND A.OPRT_DM <= #{searchEndDt}
